import styled from 'styled-components';

export const StyledHero = styled.img`
    width: 100%;
`

export const StyledIframe = styled.iframe`
    width: 100%;
    height: 100% !important;
    margin: 0 !important;
`;

export const CarouselContainer = styled.div`
    width: 100%;
    height: 100%;
`;
